import os
import hashlib

def generate_dependency_lockfile(dependencies):
    """Generate a lockfile for the given dependencies."""
    lockfile = {}
    for dependency in dependencies:
        lockfile[dependency] = hashlib.sha256(dependency).hexdigest()
    return lockfile

def update_dependency_lockfile(lockfile, dependencies):
    """Update the lockfile with the latest versions of the given dependencies."""
    for dependency in dependencies:
        if dependency not in lockfile:
            lockfile[dependency] = hashlib.sha256(dependency).hexdigest()
    return lockfile

def check_dependency_lockfile(lockfile, dependencies):
    """Check that the given dependencies are consistent with the lockfile."""
    for dependency in dependencies:
        if dependency not in lockfile or hashlib.sha256(dependency).hexdigest() != lockfile[dependency]:
            raise ValueError("Dependency {} is out of date".format(dependency))

def main():
    """Main function to demonstrate the usage of the dependency management functions."""
    dependencies = ["requests", "django"]
    lockfile = generate_dependency_lockfile(dependencies)
    print("Initial lockfile:")
    print(lockfile)
    update_dependency_lockfile(lockfile, dependencies)
    print("Updated lockfile:")
    print(lockfile)
    check_dependency_lockfile(lockfile, dependencies)
    print("Lockfile is consistent with the given dependencies.")

if __name__ == "__main__":
    main()